er-color: #27ae60; background: rgba(39,174,96,0.15); } .options li.wrong { border-color: #e74c3c; background: rgba(231,76,60,0.15); } .options li.disabled { cursor: default; opacity: 0.7; } .options li.disabled.correct { opacity: 1; } .explanation { margin-top: 15px; padding: 15px; border-radius: 8px; background: var(--bg-code); border-left: 4px solid #896f3d; font-size: 14px; line-height: 1.6; display: none; } .btn { display: inline-block; padding: 12px 30px; border: none; border-radius: 8px; font-size: 16px; cursor: pointer; } .btn-primary { background: #896f3d; color: var(--text-main); } .btn-primary:hover { background: #6d5830; } .btn-primary:disabled { background: #555; cursor: not-allowed; } .btn-restart { background: var(--bg-input); color: var(--text-main); } .btn-container { text-align: center; margin-top: 20px; } .results { display: none; } .score-circle { width: 180px; height: 180px; border-radius: 50%; margin: 20px auto; display: flex; flex-direction: column; align-items: center; justify-content: center; font-size: 48px; font-weight: bold; } .score-circle .label { font-size: 14px; } .level-excellent { background: linear-gradient(135deg, #1a3e2a, #27ae60); color: #27ae60; } .level-good { background: linear-gradient(135deg, #1a3e3e, #2980b9); color: #2980b9; } .level-average { background: linear-gradient(135deg, #3e3a1a, #f39c12); color: #f39c12; } .level-weak { background: linear-gradient(135deg, #3e1a1a, #e74c3c); color: #e74c3c; } .level-message { text-align: center; font-size: 22px; font-weight: bold; margin: 15px 0; } .level-detail { text-align: center; margin-bottom: 30px; } .cat-scores { display: grid; grid-template-columns: repeat(auto-fit, minmax(140px, 1fr)); gap: 15px; margin: 25px 0; } .cat-score-card { background: var(--bg-card); border-radius: 10px; padding: 15px; text-align: center; } .cat-score-card .cat-name { font-size: 13px; font-weight: bold; margin-bottom: 8px; } .cat-score-card .cat-pct { font-size: 28px; font-weight: bold; } .cat-score-card .cat-detail { font-size: 12px; } .start-screen { text-align: center; padding: 40px 20px; } .start-screen p { margin: 15px 0; } .tech-tags { display: flex; justify-content: center; gap: 10px; flex-wrap: wrap; margin: 20px 0; } .tech-tags span { padding: 6px 16px; border-radius: 20px; font-size: 13px; font-weight: bold; }
