const questions=[{category:"HTML",question:"Que signifie HTML ?",options:["Hyper Trainer Marking Language","Hyper Text Markup Language","Hyper Text Marketing Language","Hyper Tool Multi Language"],answer:1,explanation:"HTML = HyperText Markup Language."},{category:"HTML",question:"Quelle balise cree un lien ?",options:["<code>&lt;link&gt;</code>","<code>&lt;a&gt;</code>","<code>&lt;href&gt;</code>","<code>&lt;url&gt;</code>"],answer:1,explanation:"<code>&lt;a&gt;</code> cree des liens."},{category:"HTML",question:"Balise pour un paragraphe ?",options:["<code>&lt;para&gt;</code>","<code>&lt;p&gt;</code>","<code>&lt;text&gt;</code>","<code>&lt;pg&gt;</code>"],answer:1,explanation:"<code>&lt;p&gt;</code> = paragraphe."},{category:"HTML",question:"Balise pour inserer une image ?",options:["<code>&lt;img&gt;</code>","<code>&lt;image&gt;</code>","<code>&lt;pic&gt;</code>","<code>&lt;src&gt;</code>"],answer:0,explanation:"<code>&lt;img&gt;</code> insere une image."},{category:"HTML",question:"Attribut pour la source d'une image ?",options:["<code>href</code>","<code>src</code>","<code>link</code>","<code>alt</code>"],answer:1,explanation:"<code>src</code> = chemin du fichier."},{category:"HTML",question:"Balise du titre principal ?",options:["<code>&lt;h6&gt;</code>","<code>&lt;head&gt;</code>","<code>&lt;h1&gt;</code>","<code>&lt;title&gt;</code>"],answer:2,explanation:"<code>&lt;h1&gt;</code> = titre le plus important."},{category:"HTML",question:"Balise pour style interne ?",options:["<code>&lt;body&gt;</code>","<code>&lt;style&gt;</code>","<code>&lt;script&gt;</code>","<code>&lt;meta&gt;</code>"],answer:1,explanation:"<code>&lt;style&gt;</code> pour CSS interne."},{category:"HTML",question:"Liste non ordonnee ?",options:["<code>&lt;ol&gt;</code>","<code>&lt;ul&gt;</code>","<code>&lt;li&gt;</code>","<code>&lt;list&gt;</code>"],answer:1,explanation:"<code>&lt;ul&gt;</code> = unordered list."},{category:"CSS",question:"Que signifie CSS ?",options:["Creative Style Sheets","Cascading Style Sheets","Colorful Style Sheets","Computer Style Sheets"],answer:1,explanation:"CSS = Cascading Style Sheets."},{category:"CSS",question:"Symbole pour une classe ?",options:["<code>#</code>","<code>.</code>","<code>*</code>","<code>@</code>"],answer:1,explanation:"Le point <code>.</code> selectionne une classe."},{category:"CSS",question:"Symbole pour un identifiant ?",options:["<code>.</code>","<code>#</code>","<code>*</code>","<code>id</code>"],answer:1,explanation:"Le diese <code>#</code> selectionne un id."},{category:"CSS",question:"Couleur du texte ?",options:["<code>font-color</code>","<code>text-color</code>","<code>color</code>","<code>background</code>"],answer:2,explanation:"<code>color</code> definit la couleur du texte."},{category:"CSS",question:"Centrer un texte ?",options:["<code>align: center</code>","<code>text-align: center</code>","<code>center: true</code>","<code>margin: auto</code>"],answer:1,explanation:"<code>text-align: center</code> centre le texte."},{category:"CSS",question:"Couleur de fond ?",options:["<code>bg-color</code>","<code>background-color</code>","<code>color-bg</code>","<code>back</code>"],answer:1,explanation:"<code>background-color</code> pour le fond."},{category:"CSS",question:"Taille du texte ?",options:["<code>font-size</code>","<code>text-size</code>","<code>size</code>","<code>font</code>"],answer:0,explanation:"<code>font-size</code> controle la taille."},{category:"CSS",question:"A quoi sert display: flex ?",options:["Texte en gras","Mise en page flexible","Ajouter une image","Modifier la couleur"],answer:1,explanation:"Flexbox pour layouts flexibles."},{category:"JavaScript",question:"JavaScript est :",options:["Un langage compile","Un langage de programmation","Un serveur","Un framework"],answer:1,explanation:"JS est un langage de programmation interprete."},{category:"JavaScript",question:"Declarer une variable ?",options:["<code>var</code>","<code>int</code>","<code>string</code>","<code>dim</code>"],answer:0,explanation:"<code>var</code>, <code>let</code>, <code>const</code>."},{category:"JavaScript",question:"Afficher dans la console ?",options:["<code>print()</code>","<code>echo()</code>","<code>console.log()</code>","<code>display()</code>"],answer:2,explanation:"<code>console.log()</code> pour le debogage."},{category:"JavaScript",question:"Instruction conditionnelle ?",options:["<code>if</code>","<code>when</code>","<code>case</code>","<code>loop</code>"],answer:0,explanation:"<code>if</code> est la condition standard."},{category:"JavaScript",question:"Faire une boucle ?",options:["<code>for</code>","<code>repeat</code>","<code>each</code>","<code>loop</code>"],answer:0,explanation:"<code>for</code>, <code>while</code>, <code>do...while</code>."},{category:"JavaScript",question:"Definir une fonction ?",options:["<code>func</code>","<code>function</code>","<code>def</code>","<code>method</code>"],answer:1,explanation:"<code>function</code> declare une fonction."},{category:"JavaScript",question:"Comparaison stricte ?",options:["<code>==</code>","<code>=</code>","<code>===</code>","<code>!=</code>"],answer:2,explanation:"<code>===</code> compare type ET valeur."},{category:"JavaScript",question:"Evenement clic ?",options:["<code>onpress</code>","<code>onclick</code>","<code>onhit</code>","<code>onmouse</code>"],answer:1,explanation:"<code>onclick</code> pour le clic souris."},{category:"PHP",question:"PHP est execute cote :",options:["Client","Serveur","Navigateur","Frontend"],answer:1,explanation:"PHP est un langage serveur."},{category:"PHP",question:"Syntaxe pour ouvrir PHP ?",options:["<code>&lt;php&gt;</code>","<code>&lt;?php ?&gt;</code>","<code>&lt;script&gt;</code>","<code>&lt;code&gt;</code>"],answer:1,explanation:"<code>&lt;?php ?&gt;</code> est la syntaxe standard."},{category:"PHP",question:"Afficher du texte ?",options:["<code>print()</code>","<code>echo</code>","<code>show()</code>","<code>display()</code>"],answer:1,explanation:"<code>echo</code> est le plus utilise."},{category:"PHP",question:"Variable PHP commence par :",options:["<code>#</code>","<code>$</code>","<code>%</code>","<code>&amp;</code>"],answer:1,explanation:"Variables PHP avec <code>$</code>."},{category:"PHP",question:"Concatenation en PHP ?",options:["<code>+</code>","<code>&amp;</code>","<code>.</code>","<code>*</code>"],answer:2,explanation:"Le point <code>.</code> concatene."},{category:"PHP",question:"Structure conditionnelle ?",options:["<code>if</code>","<code>cond</code>","<code>test</code>","<code>when</code>"],answer:0,explanation:"<code>if</code> est standard."},{category:"PHP",question:"Creer un tableau ?",options:["<code>array()</code>","<code>list()</code>","<code>table()</code>","<code>data()</code>"],answer:0,explanation:"<code>array()</code> ou <code>[]</code>."},{category:"PHP",question:"Inclure un fichier ?",options:["<code>add</code>","<code>include</code>","<code>insert</code>","<code>import</code>"],answer:1,explanation:"<code>include</code> et <code>require</code>."},{category:"MySQL",question:"MySQL est :",options:["Un langage","Un SGBD","Un framework","Un serveur web"],answer:1,explanation:"MySQL = SGBDR open source."},{category:"MySQL",question:"Lire des donnees ?",options:["<code>GET</code>","<code>SELECT</code>","<code>SHOW</code>","<code>READ</code>"],answer:1,explanation:"<code>SELECT</code> lit les donnees."},{category:"MySQL",question:"Inserer des donnees ?",options:["<code>ADD</code>","<code>INSERT</code>","<code>PUT</code>","<code>CREATE</code>"],answer:1,explanation:"<code>INSERT INTO</code> ajoute des lignes."},{category:"MySQL",question:"Supprimer des donnees ?",options:["<code>DELETE</code>","<code>REMOVE</code>","<code>DROP</code>","<code>ERASE</code>"],answer:0,explanation:"<code>DELETE FROM</code> supprime des lignes."},{category:"MySQL",question:"Modifier des donnees ?",options:["<code>CHANGE</code>","<code>UPDATE</code>","<code>EDIT</code>","<code>MODIFY</code>"],answer:1,explanation:"<code>UPDATE SET</code> modifie."},{category:"MySQL",question:"Filtrer les resultats ?",options:["<code>IF</code>","<code>WHERE</code>","<code>CASE</code>","<code>WHEN</code>"],answer:1,explanation:"<code>WHERE</code> filtre les lignes."},{category:"MySQL",question:"Cle primaire ?",options:["<code>PRIMARY KEY</code>","<code>MAIN KEY</code>","<code>UNIQUE KEY</code>","<code>ID KEY</code>"],answer:0,explanation:"<code>PRIMARY KEY</code> identifie chaque ligne."},{category:"MySQL",question:"Trier les resultats ?",options:["<code>SORT</code>","<code>ORDER BY</code>","<code>GROUP</code>","<code>ALIGN</code>"],answer:1,explanation:"<code>ORDER BY</code> trie ASC ou DESC."}];
let currentQuestion=0,score=0,selectedOption=-1,answered=false,shuffledQuestions=[],answers=[],timerInterval=null,timerSeconds=0;function startTimer(){timerSeconds=0;clearInterval(timerInterval);timerInterval=setInterval(()=>{timerSeconds++;document.getElementById('timer').textContent=String(Math.floor(timerSeconds/60)).padStart(2,'0')+':'+String(timerSeconds%60).padStart(2,'0');},1000);}function stopTimer(){clearInterval(timerInterval);}function shuffle(a){const b=[...a];for(let i=b.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[b[i],b[j]]=[b[j],b[i]];}return b;}function startQuiz(){shuffledQuestions=shuffle(questions);currentQuestion=0;score=0;answers=[];document.getElementById('start-screen').style.display='none';document.getElementById('quiz-area').style.display='block';document.getElementById('results').style.display='none';showQuestion();startTimer();}function showQuestion(){selectedOption=-1;answered=false;const q=shuffledQuestions[currentQuestion],t=shuffledQuestions.length;document.getElementById('progress-text').textContent=`Question ${currentQuestion+1} / ${t}`;document.getElementById('progress-fill').style.width=((currentQuestion+1)/t*100)+'%';document.getElementById('btn-validate').style.display='inline-block';document.getElementById('btn-validate').disabled=true;document.getElementById('btn-next').style.display='none';let h=`<span class="category-badge cat-${q.category.toLowerCase()}">${q.category}</span><div class="question-text">${q.question}</div><ul class="options">`;q.options.forEach((o,i)=>{h+=`<li onclick="selectOption(${i})">${o}</li>`;});h+=`</ul><div class="explanation" id="explanation">${q.explanation}</div>`;document.getElementById('question-card').innerHTML=h;}function selectOption(i){if(answered)return;selectedOption=i;document.getElementById('btn-validate').disabled=false;document.querySelectorAll('.options li').forEach((e,x)=>{e.classList.toggle('selected',x===i);});}function validateAnswer(){if(selectedOption===-1||answered)return;answered=true;const q=shuffledQuestions[currentQuestion],c=q.answer,ok=selectedOption===c;if(ok)score++;answers.push({question:q,selected:selectedOption,correct:ok});document.querySelectorAll('.options li').forEach((e,x)=>{e.classList.add('disabled');if(x===c)e.classList.add('correct');if(x===selectedOption&&!ok)e.classList.add('wrong');});document.getElementById('explanation').style.display='block';document.getElementById('btn-validate').style.display='none';if(currentQuestion<shuffledQuestions.length-1)document.getElementById('btn-next').style.display='inline-block';else setTimeout(showResults,800);}function nextQuestion(){currentQuestion++;showQuestion();}function showResults(){stopTimer();document.getElementById('quiz-area').style.display='none';const r=document.getElementById('results');r.style.display='block';const t=shuffledQuestions.length,p=Math.round(score/t*100);let lc,m,d;if(p>=80){lc='level-excellent';m='Excellent !';d='Solide base.';}else if(p>=60){lc='level-good';m='Bon niveau !';d='Revoyez les erreurs.';}else if(p>=40){lc='level-average';m='Moyen.';d='Travaillez vos points faibles.';}else{lc='level-weak';m='A renforcer.';d='Reprenez les bases.';}const cats=['HTML','CSS','JavaScript','PHP','MySQL'];const cs={};cats.forEach(c=>cs[c]={total:0,correct:0});answers.forEach(a=>{cs[a.question.category].total++;if(a.correct)cs[a.question.category].correct++;});let ch='<div class="cat-scores">';cats.forEach(c=>{const s=cs[c],pc=s.total>0?Math.round(s.correct/s.total*100):0;let co='#e74c3c';if(pc>=80)co='#27ae60';else if(pc>=60)co='#2980b9';else if(pc>=40)co='#f39c12';ch+=`<div class="cat-score-card"><div class="cat-name"><span class="category-badge cat-${c.toLowerCase()}">${c}</span></div><div class="cat-pct" style="color:${co}">${pc}%</div><div class="cat-detail">${s.correct}/${s.total}</div></div>`;});ch+='</div>';r.innerHTML=`<div class="score-circle ${lc}">${p}%<span class="label">${score}/${t}</span></div><div class="level-message">${m}</div><div class="level-detail">${d}</div>${ch}<div class="btn-container" style="margin-top:30px"><button class="btn btn-primary" onclick="startQuiz()">Recommencer</button><button class="btn btn-restart" onclick="retryFailed()" style="margin-left:10px">Retravailler mes erreurs</button><button class="btn btn-restart" onclick="location.href='/dashboard'" style="margin-left:10px">Accueil</button></div>`;fetch('/api/scores',{method:'POST',headers:{'Content-Type':'application/json','X-CSRF-TOKEN':document.querySelector('meta[name=csrf-token]').content},body:JSON.stringify({qcm_name:'qcm11',score,total:t,percentage:p,duration_seconds:timerSeconds})});}function retryFailed(){const f=answers.filter(a=>!a.correct);if(!f.length){alert('Aucune erreur !');return;}shuffledQuestions=f.map(x=>({...x.question}));currentQuestion=0;score=0;answers=[];document.getElementById('start-screen').style.display='none';document.getElementById('quiz-area').style.display='block';document.getElementById('results').style.display='none';showQuestion();startTimer();}
</script>
